mapper.select:
SELECT * FROM user


        AND id = #{query.id}


        AND role = #{query.role}


        AND gender = #{query.gender}


        AND status = #{query.status}




        AND create_time >= #{query.createTimeStart}


        AND create_time <= #{query.createTimeEnd}




        AND update_time >= #{query.updateTimeStart}


        AND update_time <= #{query.updateTimeEnd}




        AND username LIKE CONCAT('%', #{query.username}, '%')


        AND nickname LIKE CONCAT('%', #{query.nickname}, '%')


        AND phone LIKE CONCAT('%', #{query.phone}, '%')


        AND email LIKE CONCAT('%', #{query.email}, '%')





        ORDER BY ${query.orderByClause}


        ORDER BY id
        ASC
        DESC
